const items = $input.all(); const results = [];
for (const item of items) {
  const inp = item.json; let sc = 0;
  const r_sc = inp.responsive_score || 0;
  const mob = inp.mobile_score || 100;
  const pf = inp.performance_score || 100;
  const rk = inp.page_rank || 10;
  const site = inp.sitemap_exists !== false;
  const site_url = inp.website || '';
  const pho = inp.photos || 0;
  const rev = inp.review_count || 0;
  const rat = inp.rating || 0;
  const nm = inp.business_name || '';
  const dsc = inp.description || '';
  const hrs = inp.regularOpeningHours || null;
  if (pho < 5) sc += 10; if (rev < 20) sc += 15; else if (rev < 50) sc += 8;
  if (rat > 0 && rat < 4.0) sc += 10; if (!hrs) sc += 5;
  if (!dsc || dsc.length < 50) sc += 5;
  const lwr = site_url.toLowerCase();
  if (lwr.includes('wix') || lwr.includes('squarespace') || lwr.includes('godaddy') || lwr.includes('weebly')) sc += 10;
  if (pho < 10 && rev < 30) sc += 5;
  if (r_sc > 30) sc += 20; else if (r_sc > 15) sc += 10;
  if (mob < 50) sc += 20; else if (mob < 70) sc += 10; if (pf < 50) sc += 10;
  if (!site) sc += 5; if (rk < 2) sc += 15; else if (rk < 4) sc += 8;
  const tr = sc >= 70 ? 'HOT' : sc >= 40 ? 'WARM' : 'PASS';
  results.push({json: {business_name: nm, name: nm, address: inp.address || '', phone: inp.phone || '', website: site_url, rating: rat, review_count: rev, photos: pho, description: dsc, has_hours: !!hrs, mobile_score: mob, performance_score: pf, responsive_score: r_sc, sitemap_exists: site, page_rank: rk, opportunity_score: sc, tier: tr}});
}
return results;

const places = $input.all();
const results = [];

for (const item of places) {
  const place = item.json;
  const url = place.website || place.websiteUri || null;
  let score = 0;
  const signals = [];
  let html = '';

  if (url) {
    const targetUrl = url.startsWith('http') ? url : 'https://' + url;
    try {
      const resp = await fetch(targetUrl, {
        method: 'GET',
        headers: { 'User-Agent': 'Mozilla/5.0 (compatible; WebPrinterBot/1.0)' },
        signal: AbortSignal.timeout(8000)
      });
      html = await resp.text();
    } catch(e) { signals.push('fetch_failed'); }
  } else { signals.push('no_website'); }

  if (html && !/meta[^>]+name=["']viewport["']/i.test(html)) { score += 15; signals.push('no_viewport_tag'); }
  if (html && !/@media\s*\(/i.test(html)) { score += 10; signals.push('no_media_queries'); }
  if (html && /width\s*:\s*(960|980|1024)px/i.test(html)) { score += 5; signals.push('fixed_width'); }
  if (html && /<table[^>]*layout/i.test(html)) { score += 8; signals.push('table_layout'); }
  const tc = html ? ((html.match(/<table/gi)||[]).length) : 0;
  if (tc >= 3) { score += 7; signals.push('table_layout_x' + tc); }

  // MERGE: keep all incoming data, add responsive signals on top
  results.push({
    json: {
      ...place,
      responsive_score: Number(score),
      responsive_signals: String(signals.join(',')),
      responsive_max: 45
    }
  });
}

return results;

// Process PageSpeed Data — merge onto original contractor record
const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const apiResponse = items[i].json;
  const original = $('Transform GBP Data').all()[i]?.json || {};

  try {
    const perfScore = apiResponse.lighthouseResult?.categories?.performance?.score;
    results.push({ json: {
      ...original,
      mobile_score: perfScore != null ? Math.round(perfScore * 100) : 30,
      performance_score: perfScore != null ? Math.round(perfScore * 100) : 30,
      mobile_speed_index: apiResponse.lighthouseResult?.audits?.['speed-index']?.numericValue || 0,
      total_blocking_time: apiResponse.lighthouseResult?.audits?.['total-blocking-time']?.numericValue || 0,
      largest_contentful_paint: apiResponse.lighthouseResult?.audits?.['largest-contentful-paint']?.numericValue || 0,
    }});
  } catch (error) {
    results.push({ json: {
      ...original,
      mobile_score: 30,
      performance_score: 30,
    }});
  }
}

return results;

// Process Sitemap Data — merge onto contractor record
const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const apiResponse = items[i].json;
  const prev = $('Process \u2014 PageSpeed Data').all()[i]?.json || {};

  const bodyStr = typeof apiResponse === 'string' ? apiResponse : JSON.stringify(apiResponse);
  const hasUrlset = bodyStr.includes('<urlset') || bodyStr.includes('<sitemapindex');

  results.push({ json: {
    ...prev,
    sitemap_exists: hasUrlset,
  }});
}

return results;

// Process PageRank Data — merge onto contractor record
const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const apiResponse = items[i].json;
  const prev = $('Process \u2014 Sitemap Data').all()[i]?.json || {};

  // Open PageRank returns array in response_data or status_code
  const rankData = apiResponse.response?.[0] || apiResponse;

  results.push({ json: {
    ...prev,
    page_rank: rankData.page_rank_decimal || rankData.rank || 1,
    domain_authority: rankData.domain_authority || 10,
  }});
}

return results;

// Transform GBP data with consistent fields
const item = $input.item.json;

// Ensure website URL is complete
const website = item.websiteUri || item.website || '';
const fullWebsite = website.startsWith('http') ? website : 'https://' + website;

// Return complete contractor data
return {
  json: {
    // Identity
    business_name: item.displayName?.text || item.displayName || '',
    name: item.displayName?.text || item.displayName || '',
    address: item.formattedAddress || '',
    phone: item.nationalPhoneNumber || '',
    website: fullWebsite,

    // GBP signals
    rating: parseFloat(item.rating) || 0,
    review_count: parseInt(item.userRatingCount) || 0,
    photos: (item.photos || []).length || 0,
    description: item.editorialSummary?.text || '',
    has_hours: !!item.regularOpeningHours,

    // Location
    city: item.address?.locality || '',
    state: item.address?.administrativeArea || '',
    zip: item.address?.postalCode || '',

    // Keep raw data for debugging
    _raw: item
  }
};

const results = [];

for (const item of $input.all()) {
  const people = Array.isArray(item.json?.people) ? item.json.people : [];

  // Title priority sort — owner/founder first
  const titlePriority = ['owner','co-owner','founder','president','ceo','gm','general manager','operations','manager'];
  const sorted = [...people].sort((a, b) => {
    const aIdx = titlePriority.findIndex(t => (a.title || '').toLowerCase().includes(t));
    const bIdx = titlePriority.findIndex(t => (b.title || '').toLowerCase().includes(t));
    return (aIdx === -1 ? 99 : aIdx) - (bIdx === -1 ? 99 : bIdx);
  });

  const best = sorted[0] || null;

  results.push({
    json: {
      // Contractor fields
      business_name: item.json.business_name,
      website: item.json.website,
      phone: item.json.phone,
      city: item.json.city,
      state: item.json.state,
      trade: item.json.trade,
      place_id: item.json.place_id,
      opportunity_score: item.json.opportunity_score,
      tier: item.json.tier,
      // Contact fields — null if no people found
      best_match_person_id: best?.id || null,
      first_name: best?.first_name || null,
      last_name: best?.last_name || null,
      title: best?.title || null,
      email: best?.email || null,
      confidence: best ? 'matched' : 'no_people_found'
    }
  });
}

return results;

